fileSolidName = [gcb, '/File Solid'];
set_param(fileSolidName, 'ExtGeomFileName', filenameSTL);

[shouldCompute, cached] = cacheMaskHeavyComputation( ...
    'inputPoints', inputPoints, 'R', R, 'num_vert', num_vert, ...
    'Smooth_Spline_Flag', Smooth_Spline_Flag, ...
    'patchColor', patchColor, 'markerColor', markerColor, ...
    'filenameSTL', filenameSTL, 'alpha_mod', alpha_mod);

if shouldCompute
    [pointCloud, imageMatrix] = generateSplineCylinderPointCloud(inputPoints', R, num_vert, ...
        Smooth_Spline_Flag, patchColor, markerColor, filenameSTL, alpha_mod);

    cacheMaskHeavyComputation('store', ...
        'pointCloud', pointCloud, 'imageMatrix', imageMatrix);
else
    pointCloud  = cached.pointCloud;
    imageMatrix = cached.imageMatrix;
end

